modules["components/slider"] = function()
-- src/components/slider.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local UIS = game:GetService("UserInputService")

return function(Tab, name, min, max, default, callback)
    min, max, default = min or 0, max or 100, default or 0
    local value = default
    callback = callback or function() end

    -- Main Frame (Glass)
    local Frame = Instance.new("Frame", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 50)
    Frame.BackgroundColor3 = Theme.Glass
    Frame.BackgroundTransparency = 0.75
    Frame.BorderSizePixel = 0
    Frame.ZIndex = 2
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Label with value display
    local Label = Instance.new("TextLabel", Frame)
    Label.Size = UDim2.new(1, -20, 0, 20)
    Label.Position = UDim2.new(0, 14, 0, 6)
    Label.BackgroundTransparency = 1
    Label.Text = name .. ": " .. value
    Label.TextColor3 = Theme.Text
    Label.TextSize = 13
    Label.Font = Theme.Font
    Label.TextXAlignment = Enum.TextXAlignment.Left
    Label.ZIndex = 3

    -- Slider Track (Background)
    local Track = Instance.new("Frame", Frame)
    Track.Size = UDim2.new(1, -28, 0, 6)
    Track.Position = UDim2.new(0, 14, 0, 34)
    Track.BackgroundColor3 = Theme.GlassLight
    Track.BackgroundTransparency = 0.5
    Track.ZIndex = 3
    Utils.Corner(Track, 3)

    -- Slider Fill (Gradient)
    local Fill = Instance.new("Frame", Track)
    Fill.Size = UDim2.new((value - min) / (max - min), 0, 1, 0)
    Fill.BackgroundColor3 = Theme.Accent
    Fill.BackgroundTransparency = 0.3
    Fill.ZIndex = 4
    Utils.Corner(Fill, 3)

    -- Fill Gradient
    local FillGradient = Instance.new("UIGradient", Fill)
    FillGradient.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Theme.Accent),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(150, 200, 255))
    })

    -- Slider Knob (Glass Circle)
    local Knob = Instance.new("Frame", Track)
    Knob.Size = UDim2.new(0, 16, 0, 16)
    Knob.Position = UDim2.new((value - min) / (max - min), -8, 0.5, -8)
    Knob.BackgroundColor3 = Theme.Text
    Knob.BackgroundTransparency = 0.1
    Knob.ZIndex = 5
    Utils.Corner(Knob, 8)

    -- Knob Glow
    local KnobGlow = Instance.new("Frame", Knob)
    KnobGlow.Size = UDim2.new(1, 4, 1, 4)
    KnobGlow.Position = UDim2.new(0, -2, 0, -2)
    KnobGlow.BackgroundColor3 = Theme.Accent
    KnobGlow.BackgroundTransparency = 0.8
    KnobGlow.ZIndex = 4
    Utils.Corner(KnobGlow, 10)

    -- Helper to update slider visuals based on raw value
    local function UpdateVisuals(val)
        local pct = (val - min) / (max - min)
        Utils.Tween(Fill, 0.1, {Size = UDim2.new(pct, 0, 1, 0)})
        Utils.Tween(Knob, 0.1, {Position = UDim2.new(pct, -8, 0.5, -8)})
        Label.Text = name .. ": " .. val
    end

    -- Update Function for mouse movement input
    local function UpdateFromPos(x)
        local totalWidth = Track.AbsoluteSize.X
        if totalWidth <= 0 then return end
        
        local rel = math.clamp(x - Track.AbsolutePosition.X, 0, totalWidth)
        local pct = rel / totalWidth
        value = math.floor(min + (max - min) * pct)
        
        UpdateVisuals(value)
        task.spawn(callback, value)
    end

    -- Dragging Logic with Dynamic Connections to avoid memory leaks
    local dragging = false
    local dragConnection, endConnection
    
    Track.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            UpdateFromPos(input.Position.X)
            
            -- Knob scale up
            Utils.Tween(Knob, 0.15, {Size = UDim2.new(0, 20, 0, 20)})

            dragConnection = UIS.InputChanged:Connect(function(moveInput)
                if moveInput.UserInputType == Enum.UserInputType.MouseMovement or moveInput.UserInputType == Enum.UserInputType.Touch then
                    UpdateFromPos(moveInput.Position.X)
                end
            end)

            endConnection = UIS.InputEnded:Connect(function(endInput)
                if endInput.UserInputType == Enum.UserInputType.MouseButton1 or endInput.UserInputType == Enum.UserInputType.Touch then
                    dragging = false
                    if dragConnection then
                        dragConnection:Disconnect()
                        dragConnection = nil
                    end
                    if endConnection then
                        endConnection:Disconnect()
                        endConnection = nil
                    end
                    Utils.Tween(Knob, 0.15, {Size = UDim2.new(0, 16, 0, 16)})
                end
            end)
        end
    end)

    -- Hover effect on track
    Track.MouseEnter:Connect(function()
        Utils.Tween(Track, 0.15, {BackgroundTransparency = 0.4})
    end)
    Track.MouseLeave:Connect(function()
        if not dragging then
            Utils.Tween(Track, 0.15, {BackgroundTransparency = 0.5})
        end
    end)

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        Set = function(v)
            value = math.clamp(v, min, max)
            UpdateVisuals(value)
            task.spawn(callback, value)
        end,
        Get = function() return value end
    }
end
end

modules["components/textbox"] = function()
-- src/components/textbox.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")

return function(Tab, name, placeholder, default, icon, callback)
    -- Handle parameter overloading for backwards compatibility
    if type(icon) == "function" then
        callback = icon
        icon = nil
    end
    placeholder = placeholder or "Enter text..."
    default = default or ""
    callback = callback or function() end

    -- Main Frame (Glass)
    local Frame = Instance.new("Frame", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 38)
    Frame.BackgroundColor3 = Theme.Glass
    Frame.BackgroundTransparency = 0.75
    Frame.BorderSizePixel = 0
    Frame.ZIndex = 2
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Lucide Icon Prefix (Optional)
    local IconImg, IconTxt
    if icon then
        local resolved = Icons.Get(icon) or icon
        if tostring(resolved):find("rbxassetid") or tostring(resolved):find("http") then
            IconImg = Instance.new("ImageLabel", Frame)
            IconImg.Size = UDim2.new(0, 16, 0, 16)
            IconImg.Position = UDim2.new(0, 12, 0.5, -8)
            IconImg.BackgroundTransparency = 1
            IconImg.Image = resolved
            IconImg.ImageColor3 = Theme.SubText
            IconImg.ZIndex = 3
        else
            IconTxt = Instance.new("TextLabel", Frame)
            IconTxt.Size = UDim2.new(0, 16, 1, 0)
            IconTxt.Position = UDim2.new(0, 12, 0, 0)
            IconTxt.BackgroundTransparency = 1
            IconTxt.Text = resolved
            IconTxt.TextColor3 = Theme.SubText
            IconTxt.TextSize = 12
            IconTxt.Font = Theme.Font
            IconTxt.ZIndex = 3
        end
    end

    -- Label
    local Label = Instance.new("TextLabel", Frame)
    Label.Size = UDim2.new(0, 80, 1, 0)
    Label.Position = UDim2.new(0, icon and 34 or 14, 0, 0)
    Label.BackgroundTransparency = 1
    Label.Text = name
    Label.TextColor3 = Theme.SubText
    Label.TextSize = 12
    Label.Font = Theme.Font
    Label.TextXAlignment = Enum.TextXAlignment.Left
    Label.ZIndex = 3

    -- Input Box
    local Input = Instance.new("TextBox", Frame)
    Input.Size = UDim2.new(1, icon and -130 or -110, 0, 26)
    Input.Position = UDim2.new(0, icon and 115 or 95, 0.5, -13)
    Input.BackgroundColor3 = Theme.GlassLight
    Input.BackgroundTransparency = 0.7
    Input.Text = default
    Input.PlaceholderText = placeholder
    Input.PlaceholderColor3 = Theme.Muted
    Input.TextColor3 = Theme.Text
    Input.TextSize = 12
    Input.Font = Theme.Font
    Input.ClearTextOnFocus = false
    Input.ZIndex = 3
    Utils.Corner(Input, 6)

    -- Focus Animation
    Input.Focused:Connect(function()
        Utils.Tween(Input, 0.2, {
            BackgroundTransparency = 0.6,
            Size = UDim2.new(1, icon and -125 or -105, 0, 28)
        })
        Utils.Tween(Frame, 0.2, {BackgroundTransparency = 0.7})
        if IconImg then Utils.Tween(IconImg, 0.2, {ImageColor3 = Theme.Accent}) end
        if IconTxt then Utils.Tween(IconTxt, 0.2, {TextColor3 = Theme.Accent}) end
    end)

    Input.FocusLost:Connect(function(enterPressed)
        Utils.Tween(Input, 0.2, {
            BackgroundTransparency = 0.7,
            Size = UDim2.new(1, icon and -130 or -110, 0, 26)
        })
        Utils.Tween(Frame, 0.2, {BackgroundTransparency = 0.75})
        if IconImg then Utils.Tween(IconImg, 0.2, {ImageColor3 = Theme.SubText}) end
        if IconTxt then Utils.Tween(IconTxt, 0.2, {TextColor3 = Theme.SubText}) end
        
        if enterPressed then
            task.spawn(callback, Input.Text)
        end
    end)

    -- Live text change
    Input:GetPropertyChangedSignal("Text"):Connect(function()
        task.spawn(callback, Input.Text)
    end)

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        Set = function(text) Input.Text = text end,
        Get = function() return Input.Text end
    }
end
end

modules["components/toggle"] = function()
-- src/components/toggle.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")

return function(Tab, name, default, icon, callback)
    -- Handle parameter overloading for backwards compatibility
    if type(icon) == "function" then
        callback = icon
        icon = nil
    end
    if type(default) == "function" then
        callback = default
        default = false
        icon = nil
    end
    
    local state = default or false
    callback = callback or function() end

    -- Main Frame (Glass)
    local Frame = Instance.new("Frame", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 38)
    Frame.BackgroundColor3 = Theme.Glass
    Frame.BackgroundTransparency = 0.75
    Frame.BorderSizePixel = 0
    Frame.ZIndex = 2
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Lucide Icon Prefix (Optional)
    local IconImg, IconTxt
    if icon then
        local resolved = Icons.Get(icon) or icon
        if tostring(resolved):find("rbxassetid") or tostring(resolved):find("http") then
            IconImg = Instance.new("ImageLabel", Frame)
            IconImg.Size = UDim2.new(0, 16, 0, 16)
            IconImg.Position = UDim2.new(0, 12, 0.5, -8)
            IconImg.BackgroundTransparency = 1
            IconImg.Image = resolved
            IconImg.ImageColor3 = Theme.SubText
            IconImg.ZIndex = 3
        else
            IconTxt = Instance.new("TextLabel", Frame)
            IconTxt.Size = UDim2.new(0, 16, 1, 0)
            IconTxt.Position = UDim2.new(0, 12, 0, 0)
            IconTxt.BackgroundTransparency = 1
            IconTxt.Text = resolved
            IconTxt.TextColor3 = Theme.SubText
            IconTxt.TextSize = 13
            IconTxt.Font = Theme.Font
            IconTxt.ZIndex = 3
        end
    end

    -- Label
    local Label = Instance.new("TextLabel", Frame)
    Label.Size = UDim2.new(1, icon and -100 or -80, 1, 0)
    Label.Position = UDim2.new(0, icon and 36 or 14, 0, 0)
    Label.BackgroundTransparency = 1
    Label.Text = name
    Label.TextColor3 = Theme.Text
    Label.TextSize = 13
    Label.Font = Theme.Font
    Label.TextXAlignment = Enum.TextXAlignment.Left
    Label.ZIndex = 3

    -- Toggle Button (Glass Track)
    local Btn = Instance.new("TextButton", Frame)
    Btn.Size = UDim2.new(0, 44, 0, 24)
    Btn.Position = UDim2.new(1, -54, 0.5, -12)
    Btn.BackgroundColor3 = state and Theme.Accent or Theme.GlassLight
    Btn.BackgroundTransparency = state and 0.3 or 0.6
    Btn.Text = ""
    Btn.AutoButtonColor = false
    Btn.ZIndex = 3
    Utils.Corner(Btn, 12)
    Utils.GlassBorder(Btn, 0.8)

    -- Toggle Circle (Glass Knob)
    local Circle = Instance.new("Frame", Btn)
    Circle.Size = UDim2.new(0, 18, 0, 18)
    Circle.Position = state and UDim2.new(1, -21, 0.5, -9) or UDim2.new(0, 3, 0.5, -9)
    Circle.BackgroundColor3 = Theme.Text
    Circle.BackgroundTransparency = 0.1
    Circle.ZIndex = 4
    Utils.Corner(Circle, 9)

    -- Inner glow on circle
    local CircleGlow = Instance.new("UIGradient", Circle)
    CircleGlow.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(200, 200, 220))
    })
    CircleGlow.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 0.2),
        NumberSequenceKeypoint.new(1, 0.6)
    })

    local function Update()
        Utils.Tween(Btn, 0.25, {
            BackgroundColor3 = state and Theme.Accent or Theme.GlassLight,
            BackgroundTransparency = state and 0.3 or 0.6
        })
        Utils.Tween(Circle, 0.25, {
            Position = state and UDim2.new(1, -21, 0.5, -9) or UDim2.new(0, 3, 0.5, -9)
        })
        if IconImg then
            Utils.Tween(IconImg, 0.2, {ImageColor3 = state and Theme.Accent or Theme.SubText})
        end
        if IconTxt then
            Utils.Tween(IconTxt, 0.2, {TextColor3 = state and Theme.Accent or Theme.SubText})
        end
        task.spawn(callback, state)
    end

    -- Hover effect
    Frame.MouseEnter:Connect(function()
        Utils.Tween(Frame, 0.15, {BackgroundTransparency = 0.65})
    end)
    Frame.MouseLeave:Connect(function()
        Utils.Tween(Frame, 0.15, {BackgroundTransparency = 0.75})
    end)

    Btn.MouseButton1Click:Connect(function()
        state = not state
        Update()
    end)

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        Set = function(v) state = v Update() end,
        Get = function() return state end
    }
end
end

