modules["core/notification"] = function()
-- src/core/notification.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")

local NotificationManager = {}
local Container = nil

local function GetContainer(parentScreenGui)
    if Container then return Container end
    
    Container = Instance.new("Frame", parentScreenGui)
    Container.Name = "NotificationContainer"
    Container.Size = UDim2.new(0, 280, 1, -40)
    Container.Position = UDim2.new(1, -290, 0, 20)
    Container.BackgroundTransparency = 1
    Container.ZIndex = 999999
    
    local Layout = Instance.new("UIListLayout", Container)
    Layout.Padding = UDim.new(0, 10)
    Layout.VerticalAlignment = Enum.VerticalAlignment.Bottom
    Layout.SortOrder = Enum.SortOrder.LayoutOrder
    
    return Container
end

function NotificationManager.Notify(parentScreenGui, config)
    config = config or {}
    local titleText = config.Title or "Notification"
    local descText = config.Content or "Success!"
    local duration = config.Duration or 5
    local iconStr = config.Image or "🔔" -- Text emoji or Asset ID
    
    local container = GetContainer(parentScreenGui)
    
    -- Main Toast Frame (Glass)
    local Toast = Instance.new("Frame", container)
    Toast.Size = UDim2.new(1, 0, 0, 68)
    Toast.BackgroundColor3 = Theme.Glass
    Toast.BackgroundTransparency = 0.75
    Toast.BorderSizePixel = 0
    Toast.Position = UDim2.new(1, 300, 0, 0) -- Start offscreen right
    Toast.ZIndex = 1000000
    Utils.Corner(Toast, 8)
    Utils.GlassBorder(Toast, 1)
    
    -- Slide-in shadow
    local shadow = Utils.CreateShadow(Toast, UDim2.new(1, 10, 1, 10), UDim2.new(0, -5, 0, -5), 0.5)
    shadow.ZIndex = Toast.ZIndex - 1
    
    local Icons = custom_require("core/icons")
    local resolvedIcon = Icons.Get(iconStr) or iconStr
    local isImage = tostring(resolvedIcon):find("rbxassetid") or tostring(resolvedIcon):find("http")

    -- Icon Label
    local Icon = Instance.new("TextLabel", Toast)
    Icon.Size = UDim2.new(0, 32, 0, 32)
    Icon.Position = UDim2.new(0, 12, 0.5, -16)
    Icon.BackgroundTransparency = 1
    Icon.Text = isImage and "" or resolvedIcon
    Icon.TextSize = 20
    Icon.ZIndex = Toast.ZIndex + 1
    
    local IconImg
    if isImage then
        IconImg = Instance.new("ImageLabel", Toast)
        IconImg.Size = UDim2.new(0, 24, 0, 24)
        IconImg.Position = UDim2.new(0, 16, 0.5, -12)
        IconImg.BackgroundTransparency = 1
        IconImg.Image = resolvedIcon
        IconImg.ImageColor3 = Theme.Accent -- Glow/Accent tint for Lucide icons
        IconImg.ZIndex = Toast.ZIndex + 1
    end
    
    -- Title Text
    local Title = Instance.new("TextLabel", Toast)
    Title.Size = UDim2.new(1, -60, 0, 18)
    Title.Position = UDim2.new(0, 50, 0, 10)
    Title.BackgroundTransparency = 1
    Title.Text = titleText
    Title.TextColor3 = Theme.Accent
    Title.TextSize = 13
    Title.Font = Theme.FontBold
    Title.TextXAlignment = Enum.TextXAlignment.Left
    Title.ZIndex = Toast.ZIndex + 1
    
    -- Description Text
    local Desc = Instance.new("TextLabel", Toast)
    Desc.Size = UDim2.new(1, -60, 0, 28)
    Desc.Position = UDim2.new(0, 50, 0, 28)
    Desc.BackgroundTransparency = 1
    Desc.Text = descText
    Desc.TextColor3 = Theme.Text
    Desc.TextSize = 11
    Desc.Font = Theme.Font
    Desc.TextXAlignment = Enum.TextXAlignment.Left
    Desc.TextYAlignment = Enum.TextYAlignment.Top
    Desc.TextWrapped = true
    Desc.ZIndex = Toast.ZIndex + 1
    
    -- Progress Bar Track
    local ProgressTrack = Instance.new("Frame", Toast)
    ProgressTrack.Size = UDim2.new(1, -4, 0, 2)
    ProgressTrack.Position = UDim2.new(0, 2, 1, -4)
    ProgressTrack.BackgroundColor3 = Theme.GlassLight
    ProgressTrack.BackgroundTransparency = 0.5
    ProgressTrack.ZIndex = Toast.ZIndex + 1
    Utils.Corner(ProgressTrack, 1)
    
    -- Progress Bar Fill
    local ProgressFill = Instance.new("Frame", ProgressTrack)
    ProgressFill.Size = UDim2.new(1, 0, 1, 0)
    ProgressFill.BackgroundColor3 = Theme.Accent
    ProgressFill.ZIndex = Toast.ZIndex + 2
    Utils.Corner(ProgressFill, 1)
    
    -- Slide-in Tween
    Utils.Tween(Toast, 0.35, {Position = UDim2.new(0, 0, 0, 0)})
    
    -- Progress bar shrinking Tween
    Utils.Tween(ProgressFill, duration, {Size = UDim2.new(0, 0, 1, 0)})
    
    -- Auto-dismiss delay
    task.delay(duration, function()
        Utils.Tween(Toast, 0.35, {
            Position = UDim2.new(1, 300, 0, 0),
            BackgroundTransparency = 1
        })
        Utils.Tween(Title, 0.25, {TextTransparency = 1})
        Utils.Tween(Desc, 0.25, {TextTransparency = 1})
        Utils.Tween(Icon, 0.25, {TextTransparency = 1})
        if IconImg then
            Utils.Tween(IconImg, 0.25, {ImageTransparency = 1})
        end
        
        task.delay(0.35, function()
            Toast:Destroy()
        end)
    end)
end

return NotificationManager

end

modules["core/theme"] = function()
-- src/core/theme.lua
-- Premium Obsidian/Cyan Dark Theme with Reactive Updates

local Theme = {
    Values = {
        -- Base Colors (Obsidian Dark with Vibrant Cyan Accents)
        Background = Color3.fromRGB(10, 10, 14),
        BackgroundTransparency = 0.35, -- Let neon blobs shine through beautifully
        Glass = Color3.fromRGB(18, 18, 26),
        GlassLight = Color3.fromRGB(28, 28, 40),
        GlassTransparency = 0.45, -- Enhanced transparency for glassmorphism
        Accent = Color3.fromRGB(0, 180, 255),
        AccentHover = Color3.fromRGB(30, 200, 255),
        AccentDim = Color3.fromRGB(0, 120, 180),
        
        -- Text Colors
        Text = Color3.fromRGB(255, 255, 255),
        SubText = Color3.fromRGB(170, 175, 190),
        Muted = Color3.fromRGB(100, 105, 120),
        
        -- Glass Effect Properties
        GlassBorder = Color3.fromRGB(45, 45, 62),
        GlassBorderTransparency = 0.4,
        GlassHighlight = Color3.fromRGB(255, 255, 255),
        
        -- Shadows & Depth
        ShadowColor = Color3.fromRGB(0, 0, 0),
        ShadowTransparency = 0.5,
        
        -- Fonts
        Font = Enum.Font.GothamMedium,
        FontBold = Enum.Font.GothamBold,
        FontLight = Enum.Font.Gotham,
        
        -- Animation
        TweenTime = 0.2,
        EasingStyle = Enum.EasingStyle.Quart,
        EasingDirection = Enum.EasingDirection.Out,
        
        -- Liquid Neon Blobs
        Blob1Color = Color3.fromRGB(0, 180, 255),
        Blob2Color = Color3.fromRGB(180, 0, 255),
        BlobTransparency = 0.72, -- Visible yet elegant
        BlobSpeed = 1.0,
    }
}

-- Simple reactive event listener system (Pure Lua Signal)
local Signal = { Listeners = {} }
function Signal:Connect(callback)
    table.insert(self.Listeners, callback)
    return {
        Disconnect = function()
            local idx = table.find(self.Listeners, callback)
            if idx then table.remove(self.Listeners, idx) end
        end
    }
end
function Signal:Fire(arg)
    for _, callback in ipairs(self.Listeners) do
        task.spawn(callback, arg)
    end
end

Theme.Changed = Signal

-- Update theme values and trigger event listeners
function Theme:Update(newValues)
    local oldTheme = {}
    for k, v in pairs(Theme.Values) do
        oldTheme[k] = v
    end

    for k, v in pairs(newValues) do
        if Theme.Values[k] ~= nil then
            Theme.Values[k] = v
        end
    end
    Theme.Changed:Fire(oldTheme)
end

-- Allow direct access to values (e.g., Theme.Accent)
setmetatable(Theme, {
    __index = function(_, key)
        return Theme.Values[key]
    end
})

return Theme
end

modules["core/utils"] = function()
-- src/core/utils.lua
local TweenService = game:GetService("TweenService")
local Theme = custom_require("core/theme")

local Utils = {}

-- Enhanced Tween with theme defaults
function Utils.Tween(obj, time, props)
    time = time or Theme.TweenTime
    local info = TweenInfo.new(time, Theme.EasingStyle, Theme.EasingDirection)
    local tween = TweenService:Create(obj, info, props)
    tween:Play()
    return tween
end

-- Create rounded corners
function Utils.Corner(obj, radius)
    local c = Instance.new("UICorner", obj)
    c.CornerRadius = UDim.new(0, radius or 8)
    return c
end

-- Create glass border with gradient for realistic glass refraction
function Utils.GlassBorder(obj, thickness)
    thickness = thickness or 1
    
    local stroke = Instance.new("UIStroke", obj)
    stroke.Color = Color3.fromRGB(255, 255, 255)
    stroke.Thickness = thickness
    stroke.Transparency = 0.5
    
    local gradient = Instance.new("UIGradient", stroke)
    gradient.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
        ColorSequenceKeypoint.new(0.4, Theme.GlassBorder),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(30, 30, 45))
    })
    gradient.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 0.4),  -- Glowing top edge highlight
        NumberSequenceKeypoint.new(0.4, 0.7), -- Glass border default
        NumberSequenceKeypoint.new(1, 0.9)   -- Darker bottom edge shadow
    })
    gradient.Rotation = 45
    
    return stroke
end

-- Create glass effect (layered transparency + gradient)
function Utils.CreateGlass(parent, size, position, transparency)
    transparency = transparency or Theme.GlassTransparency
    
    -- Base glass layer
    local glass = Instance.new("Frame", parent)
    glass.Size = size or UDim2.new(1, 0, 1, 0)
    glass.Position = position or UDim2.new(0, 0, 0, 0)
    glass.BackgroundColor3 = Theme.Glass
    glass.BackgroundTransparency = transparency
    glass.BorderSizePixel = 0
    glass.ZIndex = 1
    
    -- Gradient overlay for depth
    local gradient = Instance.new("UIGradient", glass)
    gradient.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
        ColorSequenceKeypoint.new(0.5, Color3.fromRGB(220, 220, 240)),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(150, 150, 180))
    })
    gradient.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 0.92),
        NumberSequenceKeypoint.new(0.5, 0.96),
        NumberSequenceKeypoint.new(1, 0.88)
    })
    gradient.Rotation = 45
    
    Utils.Corner(glass, 8)
    Utils.GlassBorder(glass, 1)
    
    return glass
end

-- Create soft shadow
function Utils.CreateShadow(parent, size, offset, transparency)
    local shadow = Instance.new("Frame", parent)
    shadow.Size = size or UDim2.new(1, 10, 1, 10)
    shadow.Position = offset or UDim2.new(0, -5, 0, -5)
    shadow.BackgroundColor3 = Theme.ShadowColor
    shadow.BackgroundTransparency = transparency or Theme.ShadowTransparency
    shadow.ZIndex = parent.ZIndex - 1
    Utils.Corner(shadow, 12)
    
    -- Blur effect
    local blur = Instance.new("ImageLabel", shadow)
    blur.Size = UDim2.new(1, 0, 1, 0)
    blur.BackgroundTransparency = 1
    blur.Image = "rbxassetid://5554236805" -- Soft blur texture
    blur.ImageColor3 = Theme.ShadowColor
    blur.ImageTransparency = 0.65
    blur.ScaleType = Enum.ScaleType.Slice
    blur.SliceCenter = Rect.new(23, 23, 277, 277)
    
    return shadow
end

-- Create glowing background blob for liquid neon effect
function Utils.CreateGlowBlob(parent, color, size, position)
    local blob = Instance.new("ImageLabel", parent)
    blob.Size = size or UDim2.new(0, 250, 0, 250)
    blob.Position = position or UDim2.new(0, 0, 0, 0)
    blob.BackgroundTransparency = 1
    blob.Image = "rbxassetid://5554236805" -- Soft blur texture
    blob.ImageColor3 = color
    blob.ImageTransparency = Theme.BlobTransparency
    blob.ZIndex = 0
    return blob
end

-- Make frame draggable with smooth physics
function Utils.MakeDraggable(frame, dragObj)
    local UIS = game:GetService("UserInputService")
    local dragging, dragStart, startPos
    local dragConnection, endConnection

    dragObj.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            dragStart = input.Position
            startPos = frame.Position
            
            -- Lift effect (scale up + glow highlight)
            Utils.Tween(frame, 0.2, {
                Size = UDim2.new(
                    frame.Size.X.Scale, frame.Size.X.Offset + 4,
                    frame.Size.Y.Scale, frame.Size.Y.Offset + 4
                )
            })
            
            dragConnection = UIS.InputChanged:Connect(function(moveInput)
                if moveInput.UserInputType == Enum.UserInputType.MouseMovement or moveInput.UserInputType == Enum.UserInputType.Touch then
                    local delta = moveInput.Position - dragStart
                    frame.Position = UDim2.new(
                        startPos.X.Scale, startPos.X.Offset + delta.X,
                        startPos.Y.Scale, startPos.Y.Offset + delta.Y
                    )
                end
            end)
            
            endConnection = UIS.InputEnded:Connect(function(endInput)
                if endInput.UserInputType == Enum.UserInputType.MouseButton1 or endInput.UserInputType == Enum.UserInputType.Touch then
                    dragging = false
                    if dragConnection then
                        dragConnection:Disconnect()
                        dragConnection = nil
                    end
                    if endConnection then
                        endConnection:Disconnect()
                        endConnection = nil
                    end
                    Utils.Tween(frame, 0.2, {
                        Size = UDim2.new(
                            frame.Size.X.Scale, frame.Size.X.Offset - 4,
                            frame.Size.Y.Scale, frame.Size.Y.Offset - 4
                        )
                    })
                end
            end)
        end
    end)
end

-- Create hover effect
function Utils.HoverEffect(obj, hoverColor, normalColor)
    hoverColor = hoverColor or Theme.GlassLight
    normalColor = normalColor or Theme.Glass
    
    obj.MouseEnter:Connect(function()
        Utils.Tween(obj, 0.15, {BackgroundColor3 = hoverColor, BackgroundTransparency = 0.6})
    end)
    
    obj.MouseLeave:Connect(function()
        Utils.Tween(obj, 0.15, {BackgroundColor3 = normalColor, BackgroundTransparency = 0.75})
    end)
end

-- Style custom scrollbar
function Utils.StyleScroll(scroll)
    scroll.ScrollBarThickness = 3
    scroll.ScrollBarImageColor3 = Theme.Accent
    scroll.ScrollBarImageTransparency = 0.5
    scroll.BorderSizePixel = 0
end

return Utils
end

